    sheetData.value.parent_id = parent.id;
    sheetData.value.sys_code = parent.sys_code;
    sheetData.value.path = parent.path + '/';
    sheetData.value.alias = parent.alias + '/';
  }
  dialogShow.value = true;
}

//表单完成
function formDone(res: { status?: boolean; message?: string }) {
