    dialogShow.value = false;
  });
}

//提交
function btnSubmit() {
  formRef.value
    ?.validate((errors: any) => {
      if (!errors) {
        if (formState.value == 'add') {
          Add(sheetData.value).then((res) => {
            formDone(res);
          });
        } else {
          Update(sheetData.value).then((res) => {
            formDone(res);
          });
        }
      }
    })
    .catch((err: Error) => {
      window.$message.warning(err.message);
    });
}

//取消
function btnCancel() {
  sheetData.value = {} as Sys_menu_Class;
  dialogShow.value = false;
}
